mapper.update:
UPDATE member_wallet
SET point_balance = point_balance - #{delta},
    modify_dt = NOW()
WHERE member_seq = #{memberSeq}
  AND point_balance >= #{delta}

UPDATE member_wallet
SET point_balance = point_balance - #{cost},
    iron_qty = iron_qty + #{qty},
    modify_dt = NOW()
WHERE member_seq = #{memberSeq}
  AND point_balance >= #{cost}

UPDATE member_wallet
SET iron_qty = iron_qty - #{ironCost},
    silver_qty = silver_qty + #{silverGain},
    modify_dt = NOW()
WHERE member_seq = #{memberSeq}
  AND iron_qty >= #{ironCost}

UPDATE member_wallet
SET silver_qty = silver_qty - #{silverCost},
    gold_qty = gold_qty + #{goldGain},
    modify_dt = NOW()
WHERE member_seq = #{memberSeq}
  AND silver_qty >= #{silverCost}

UPDATE member_wallet
SET gold_qty = gold_qty - #{goldCost},
    diamond_qty = diamond_qty + #{diamondGain},
    modify_dt = NOW()
WHERE member_seq = #{memberSeq}
  AND gold_qty >= #{goldCost}

mapper.insert:
INSERT INTO member_wallet_ledger (
    member_seq, reason_code, summary,
    point_delta, iron_delta, silver_delta, gold_delta, diamond_delta,
    create_dt, create_id
) VALUES (
    #{memberSeq}, #{reasonCode}, #{summary},
    #{pointDelta}, #{ironDelta}, #{silverDelta}, #{goldDelta}, #{diamondDelta},
    NOW(), #{createId}
)

mapper.select:
SELECT l.member_seq AS memberSeq, l.reason_code AS reasonCode, COALESCE(SUM(l.point_delta), 0) AS pointsEarned FROM member_wallet_ledger l INNER JOIN MEMBER m ON m.MEMBER_SEQ = l.member_seq AND m.USE_YN = 'Y' WHERE l.point_delta > 0 AND l.create_dt >= #{fromInclusive} AND l.create_dt < #{toExclusive} AND l.reason_code NOT IN ('POINT_GIFT_SENT', 'POINT_GIFT_RECEIVED') AND l.member_seq IN
#{sid}
GROUP BY l.member_seq, l.reason_code HAVING SUM(l.point_delta) > 0 ORDER BY l.member_seq ASC, SUM(l.point_delta) DESC
